// as a base64 JSON blob inside an HTML comment, so it syncs across devices and
// survives Markdown/YAML quirks (titles can be any UTF-8 text).
const LIST_META_RE = /<!--task-deck-lists:([A-Za-z0-9+/=]*)-->/;

