    id: frontmatterValue(markdown, "kanban-card-id") || "",
    boardId: frontmatterValue(markdown, "kanban-board-id") || "",
    listId: frontmatterValue(markdown, "kanban-list-id") || "",
    listTitle: frontmatterValue(markdown, "task-deck-list") || "",
